function r(i){const e=new Date().getHours();return e>=23||e<5?{headline:"مين اللي مصحّيكِ دلوقتي؟! 😂",sub:`والله هقتّله! أهلاً يا ${i}`,emoji:"🌙"}:e>=5&&e<12?{headline:`مساء الفل يا ${i}! 😄`,sub:"(إيه إيه صبح ولا مساء؟ مش مهم، يلا نشتغل 😂)",emoji:"☀️"}:e>=12&&e<18?{headline:`مساء الخير يا ${i}! ✨`,sub:"يلا بينا نعمل حاجة حلوة النهارده!",emoji:"🌸"}:{headline:`مساء الفل يا ${i}! 🌙`,sub:"إيه أخبار الشغل النهارده؟",emoji:"🌙"}}export{r as g};
